compliant:
public void Foo(Bar a, int[] b)
{
  throw new ArgumentException("My error message", nameof(a)); // Compliant: 'a' matches parameter
  throw new ArgumentNullException(nameof(b)); // Compliant: 'b' matches parameter
  throw new ArgumentOutOfRangeException(nameof(a), a, "Value is out of range"); // Compliant
}
